                            parentDocumentIndex,
                            useEvaluatedItems: false,
                            useEvaluatedProperties: false,
                            itemIndex,
                            evaluationPath: evaluationPath,
                            schemaEvaluationPath: SchemaLocationProvider);
                }
            }
        }
    }
}
